query:
-- Get superadmin user ID first
SET @superadmin_id = (SELECT id FROM users WHERE role = 'admin' LIMIT 1);

-- Delete all data while preserving superadmin
DELETE FROM rentalContracts;
DELETE FROM invoices;
DELETE FROM vehicles;
DELETE FROM clients;
DELETE FROM companyProfiles;
DELETE FROM users WHERE id != @superadmin_id;

-- Verify superadmin still exists
SELECT COUNT(*) as remaining_users FROM users;

